    71→  // request/response. Should we add an identifier to the HealthCheckSpecifier
    72→  // to bind with the response?
    73→  rpc FetchHealthCheck(HealthCheckRequestOrEndpointHealthResponse) returns (HealthCheckSpecifier) {
